// Correlate sensor offline with driver install (Falcon + Sentinel)
// 1. Pull Falcon hosts with last-seen gap > 5 min
// 2. Cross-reference to 7045 events on those hosts in the 10 min prior to gap
SecurityEvent
| where EventID == 7045
| where ServiceType == "kernel mode driver"
| join kind=inner (
    // replace with your Falcon offline event table
    FalconOfflineHosts
    | project DeviceName, OfflineAt
) on Computer == DeviceName
| where TimeGenerated between ((OfflineAt - 10m) .. OfflineAt)
| project TimeGenerated, Computer, ServiceName, ServiceFileName, OfflineAt

// Correlate SharePoint download with egress anomaly on same host
// Step 1: identify hosts with large SharePoint download sessions
// Step 2: pull NetFlow for those hosts in the 24h following the download
// Step 3: flag sustained egress >500 MB to non-CDN, non-Microsoft IP ranges
// Proxy/firewall log query will vary by vendor (Zscaler, Palo Alto, Cisco)
// Generic pattern:
CommonSecurityLog
| where TimeGenerated > ago(30d)
| where DestinationPort == 443
| where not(ipv4_is_in_range(DestinationIP, "13.64.0.0/11"))  // exclude Azure
| summarize total_bytes = sum(SentBytes) by bin(TimeGenerated, 1h), SourceHostName, DestinationIP
| where total_bytes > 500000000  // 500 MB
| sort by total_bytes desc
